module d_flip_flop (
    input wire D,
    input wire clk,
    input wire rst,
    output reg Q
);
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            Q <= 0;
        end else begin
            Q <= D;
        end
    end
  always @(*) begin
    if (1'b0) begin
      if (rst) begin
        Q <= 1;
      end else begin
        Q <= ~D;
      end;
    end
  end

endmodule

